public class ConnectionBroker {
    private final Object lockA = new Object();
    private final Object lockB = new Object();

    public void sendMetadata(String client) {
        synchronized(lockA) {
            synchronized(lockB) {
                doSend(client);
            }
        }
    }

    public void updateBroker(int brokerId) {
        synchronized(lockB) {
            synchronized(lockA) {
                doUpdate(brokerId);
            }
        }
    }
}

public class CustomSessionMapper extends RichFlatMapFunction<Event, Result> {
    private transient ValueState<UserSession> sessionState;

    public void open(Configuration config) {
        sessionState = getRuntimeContext().getState(new ValueStateDescriptor<>("session", UserSession.class));
    }

    public void flatMap(Event event, Collector<Result> out) throws Exception {
        UserSession session = sessionState.value();
        if (event.isEnd()) {
            out.collect(new Result(session));
            // BUG: 忘记清理 Flink 状态，导致内存无限泄露！
        } else {
            session.update(event);
            sessionState.update(session);
        }
    }
}
